sections.matlabComparison:
% MATLAB equivalent
fs = 1000;
t = 0:1/fs:1-1/fs;
x = 0.5*sin(2*pi*50*t) + sin(2*pi*120*t);
N = length(x);
X = fft(x);
freqs = (-N/2:N/2-1)*(fs/N);
X_shifted = fftshift(X);
plot(freqs, abs(X_shifted)/N);

% MATLAB equivalent
fs = 1e6;
N = 100000;
t = (0:N-1)/fs;
noise = sqrt(1e-3) * randn(1, N);
signal = 0.1 * cos(2*pi*200e3*t);
x = signal + noise;
[Pxx, f] = pwelch(x, hann(1024), 512, 1024, fs);
semilogx(f, 10*log10(Pxx));
